  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // 100 requests per window per IP
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// --- Disable fingerprinting ---
app.disable('x-powered-by');

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate query parameters if pagination is added
  const page = parseInt(req.query.page, 10);
  const limit = parseInt(req.query.limit, 10);

  if (req.query.page !== undefined && (isNaN(page) || page < 1)) {
    return res.status(400).json({ error: 'Invalid page parameter' });
  }
  if (req.query.limit !== undefined && (isNaN(limit) || limit < 1 || limit > 100)) {
    return res.status(400).json({ error: 'Invalid limit parameter (1-100)' });
  }

  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

